// src/tools/testing.ts
function registerTestingTools(server, client) {
  server.registerTool(
    "sf_run_apex_tests",
    {
      title: "Run Apex Tests",
      description: `Execute Apex test classes asynchronously and get back a test run ID.

Returns immediately with a testRunId. Use sf_get_apex_test_results or sf_resume_operation to poll for completion.

Args:
  - class_names (string[]): Apex test class names to run
  - suite_names (string[]): Apex test suite names (alternative to class_names)
  - test_level: RunSpecifiedTests | RunLocalTests | RunAllTestsInOrg

Returns: { testRunId: "..." } \u2014 use this ID with sf_get_apex_test_results.

Examples:
  - { class_names: ["AccountTriggerTest", "OpportunityServiceTest"] }
  - { test_level: "RunLocalTests" }  \u2192 runs all local (non-managed-package) tests`,
      inputSchema: RunApexTestsSchema,
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: false, openWorldHint: false }
    },
    async ({ class_names, suite_names, test_level }) => {
      const result = await client.runApexTests({
        classNames: class_names,
        suiteNames: suite_names,
        testLevel: test_level
      });
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            ...result,
            next_step: `Call sf_get_apex_test_results with testRunId "${result.testRunId}" to get results, or sf_resume_operation with { operation_type: "apexTest", operation_id: "${result.testRunId}" } to wait for completion.`
          }, null, 2)
        }],
        structuredContent: result
      };
    }
  );
  server.registerTool(
    "sf_get_apex_test_results",
    {
      title: "Get Apex Test Results",
      description: `Get results for a completed (or in-progress) Apex test run.

Args:
  - test_run_id (string): ID returned by sf_run_apex_tests

Returns: Summary (pass/fail/skip counts), individual test results with stack traces, and code coverage.

Use sf_resume_operation first if the test run is still in progress.`,
      inputSchema: TestRunIdSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ test_run_id }) => {
      const result = await client.getApexTestResults(test_run_id);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_resume_operation",
    {
      title: "Resume / Poll Async Operation",
      description: `Poll an async Salesforce operation until it completes or times out.

Handles: Apex test runs, metadata deploys, metadata retrieves, and async Apex jobs.

Args:
  - operation_type: "apexTest" | "deploy" | "retrieve" | "apexJob"
  - operation_id: The ID returned by the initiating tool
  - max_poll_seconds: Max wait time in seconds (default: 60, max: 300)
  - poll_interval_seconds: Polling frequency in seconds (default: 5)

Returns: Final status when complete, or a timeout message with the operation ID to retry.

Examples:
  - Wait for test run: { operation_type: "apexTest", operation_id: "707xx0000001234", max_poll_seconds: 120 }
  - Wait for deploy: { operation_type: "deploy", operation_id: "0Afxx0000001234", max_poll_seconds: 180 }`,
      inputSchema: ResumeOperationSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ operation_type, operation_id, max_poll_seconds, poll_interval_seconds }) => {
      const result = await client.pollAsyncOperation({
        operationType: operation_type,
        operationId: operation_id,
        maxPollSeconds: max_poll_seconds,
        pollIntervalSeconds: poll_interval_seconds
      });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_run_agent_test",
    {
      title: "Run Agentforce Agent Test",
      description: `Execute an Agentforce (Einstein) agent test suite.

Args:
  - agent_test_suite_id (string): AiEvaluationDefinition or BotVersion ID
  - bot_id (string, optional): Specific Bot/Agent ID to target

Returns: Test run ID and initial status. Use sf_get_agent_test_results for outcome.

Use sf_list_agent_test_suites first to find the correct test suite ID.`,
      inputSchema: RunAgentTestSchema,
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: false, openWorldHint: false }
    },
    async ({ agent_test_suite_id, bot_id }) => {
      const result = await client.runAgentTest({ agentTestSuiteId: agent_test_suite_id, botId: bot_id });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_list_agent_test_suites",
    {
      title: "List Agent Test Suites",
      description: `List all Agentforce agent test suites and bot versions in the org.

No args required.

Returns: Available test suite IDs to use with sf_run_agent_test.`,
      inputSchema: external_exports.object({}).strict(),
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async () => {
      const suites = await client.listAgentTestSuites();
      const result = { count: suites.length, testSuites: suites };
      return ok(result);
    }
  );
  server.registerTool(
    "sf_get_agent_test_results",
    {
      title: "Get Agent Test Results",
      description: `Get results from an Agentforce agent test run.

Args:
  - run_id (string): Test run ID returned by sf_run_agent_test

Returns: Agent test outcomes including response quality, intent matching, and action accuracy.`,
      inputSchema: AgentTestRunIdSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ run_id }) => {
      const result = await client.getAgentTestResults(run_id);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_run_code_analysis",
    {
      title: "Run Code Analysis on Apex Classes",
      description: `Perform static code analysis on Apex classes using the Tooling API.

Checks: compilation errors, symbol table issues, and code quality via container-based compile.

Args:
  - class_names (string[]): Apex class names to analyze
  - trigger_names (string[]): Apex trigger names to analyze

Returns: Compile check results, symbol analysis, and issues found.

Example:
  { class_names: ["AccountService", "OpportunityTriggerHandler"] }

For deeper antipattern detection (SOQL in loops, DML in loops, hardcoded IDs, etc.), use sf_scan_apex_antipatterns.`,
      inputSchema: CodeAnalysisSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ class_names, trigger_names, rules }) => {
      const result = await client.runCodeAnalysis({
        classNames: class_names,
        triggerNames: trigger_names,
        rules
      });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_scan_apex_antipatterns",
    {
      title: "Scan Apex Classes for Antipatterns",
      description: `Scan Apex class bodies for critical governor limit violations and code quality issues.

Detects:
  \u{1F534} CRITICAL: SOQL inside loops (hits 100 query limit), DML inside loops (hits 150 DML limit)
  \u{1F7E0} HIGH: Empty catch blocks, classes declared 'without sharing'
  \u{1F7E1} WARNING: SOQL without LIMIT clauses, hardcoded Salesforce IDs
  \u{1F535} INFO: System.debug() left in code, @future(callout=true) antipatterns

Args:
  - class_names (string[]): Apex class names to scan (max 20 at a time)

Returns: Per-class issue list with line numbers, severity, description, and recommended fix.

Example:
  { class_names: ["AccountTriggerHandler", "LeadConversionService", "OpportunityBatch"] }`,
      inputSchema: AntipatternScanSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ class_names }) => {
      const result = await client.scanApexAntipatterns({ classNames: class_names });
      return ok(result);
    }
  );
}

// src/tools/devops.ts
function registerDevOpsTools(server, client) {
  server.registerTool(
    "sf_deploy_metadata",
    {
      title: "Deploy Metadata",
      description: `Deploy Salesforce metadata (Apex, Flows, Objects, Fields, Layouts, etc.) to an org using the Metadata API.

Accepts a base64-encoded ZIP file in MDAPI format. Returns a deployId immediately \u2014 use sf_get_deploy_status or sf_resume_operation to track completion.

Args:
  - zip_base64 (string): Base64-encoded ZIP of metadata in MDAPI format
  - check_only (boolean): Validate without committing changes (default: false)
  - test_level: NoTestRun | RunSpecifiedTests | RunLocalTests | RunAllTestsInOrg
  - run_tests (string[]): Specific test classes if test_level = RunSpecifiedTests
  - ignore_warnings (boolean): Continue even with warnings (default: false)
  - rollback_on_error (boolean): Roll back all on any failure (default: true)

Returns: { deployId } \u2014 use with sf_resume_operation to wait for result.

MDAPI ZIP structure:
  package.xml
  classes/
    AccountService.cls
    AccountService.cls-meta.xml
  flows/
    My_Flow.flow-meta.xml

Examples:
  - Validate-only: { zip_base64: "...", check_only: true, test_level: "RunLocalTests" }
  - Full deploy: { zip_base64: "...", test_level: "NoTestRun" }`,
      inputSchema: DeployMetadataSchema,
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: false, openWorldHint: false }
    },
    async ({ zip_base64, check_only, test_level, run_tests, ignore_warnings, rollback_on_error }) => {
      const result = await client.deployMetadata({
        zipBase64: zip_base64,
        options: {
          checkOnly: check_only,
          testLevel: test_level,
          runTests: run_tests,
          ignoreWarnings: ignore_warnings,
          rollbackOnError: rollback_on_error
        }
      });
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            ...result,
            next_step: `Call sf_resume_operation with { operation_type: "deploy", operation_id: "${result.deployId}" } to wait for completion, or sf_get_deploy_status to check immediately.`
          }, null, 2)
        }],
        structuredContent: result
      };
    }
  );
  server.registerTool(
    "sf_get_deploy_status",
    {
      title: "Get Deploy Status",
      description: `Get the current status of a metadata deploy operation.

Args:
  - deploy_id (string): Deploy request ID from sf_deploy_metadata

Returns: Full deploy result including status, component successes/failures, test results, and error details.

Status values: Queued \u2192 InProgress \u2192 Succeeded | Failed | Canceled | SucceededPartial`,
      inputSchema: DeployIdSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ deploy_id }) => {
      const result = await client.getDeployStatus(deploy_id);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_retrieve_metadata",
    {
      title: "Retrieve Metadata",
      description: `Retrieve Salesforce metadata from an org to inspect or back up. Returns a retrieveId \u2014 use sf_get_retrieve_status to get the zip when done.

Args:
  - specific_types (array): Metadata types and members to retrieve:
    - name: Metadata type (e.g. "ApexClass", "Flow", "CustomObject", "Layout", "PermissionSet")
    - members: Component names \u2014 use "*" for all, or specific names
  - package_names (string[]): Installed package names to retrieve
  - api_version (string): Override API version (e.g. "60.0")

Returns: { retrieveId } \u2014 use with sf_resume_operation or sf_get_retrieve_status.

Common metadata types: ApexClass, ApexTrigger, AuraDefinitionBundle, CustomApplication, CustomField,
CustomLabel, CustomObject, CustomTab, Flow, Layout, LightningComponentBundle, PermissionSet,
Profile, Queue, Report, ReportType, Role, SharingRules, ValidationRule, Workflow

Examples:
  - Get all Apex classes: { specific_types: [{ name: "ApexClass", members: ["*"] }] }
  - Get specific flow + object: { specific_types: [{ name: "Flow", members: ["My_Approval_Flow"] }, { name: "CustomObject", members: ["Deal__c"] }] }
  - Get permission sets: { specific_types: [{ name: "PermissionSet", members: ["*"] }] }`,
      inputSchema: RetrieveMetadataSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: false, openWorldHint: false }
    },
    async ({ specific_types, package_names, api_version }) => {
      const result = await client.retrieveMetadata({
        specificTypes: specific_types,
        packageNames: package_names,
        apiVersion: api_version
      });
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            ...result,
            next_step: `Call sf_resume_operation with { operation_type: "retrieve", operation_id: "${result.retrieveId}" } to wait for completion, then sf_get_retrieve_status to get the base64 ZIP.`
          }, null, 2)
        }],
        structuredContent: result
      };
    }
  );
  server.registerTool(
    "sf_get_retrieve_status",
    {
      title: "Get Retrieve Status & Download",
      description: `Get the current status of a metadata retrieve. When complete, returns the base64-encoded ZIP.

Args:
  - retrieve_id (string): Retrieve request ID from sf_retrieve_metadata

Returns: Status and, when Succeeded, a zipFile (base64) containing all retrieved metadata.`,
      inputSchema: RetrieveIdSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ retrieve_id }) => {
      const result = await client.getRetrieveStatus(retrieve_id);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_assign_permission_set",
    {
      title: "Assign Permission Set to User",
      description: `Assign a Permission Set to a Salesforce user. Safe to call if already assigned (returns early).

Args:
  - user_id (string): Salesforce User ID
  - permission_set_name (string): API name of the Permission Set (not label), e.g. 'Sales_Manager_Permissions'

Returns: Success confirmation with assignment details.

Examples:
  - { user_id: "0051a00000XYZ", permission_set_name: "Sales_Manager_Permissions" }
  - { user_id: "0051a00000XYZ", permission_set_name: "API_Access" }

Use sf_list_permission_sets to find valid permission set names.`,
      inputSchema: AssignPermSetSchema,
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ user_id, permission_set_name }) => {
      const result = await client.assignPermissionSet({ userId: user_id, permissionSetName: permission_set_name });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_revoke_permission_set",
    {
      title: "Revoke Permission Set from User",
      description: `Remove a Permission Set assignment from a user.

Args:
  - user_id (string): Salesforce User ID
  - permission_set_name (string): API name of the Permission Set to revoke

Returns: Success confirmation.`,
      inputSchema: AssignPermSetSchema,
      annotations: { readOnlyHint: false, destructiveHint: true, idempotentHint: true, openWorldHint: false }
    },
    async ({ user_id, permission_set_name }) => {
      const result = await client.revokePermissionSet({ userId: user_id, permissionSetName: permission_set_name });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_list_all_orgs",
    {
      title: "List All Authorized Orgs",
      description: `List all Salesforce orgs authorized on this machine via the Salesforce CLI.

Requires: Salesforce CLI (sf) installed and orgs authenticated via 'sf org login web'.

No args required.

Returns: All authorized orgs (scratch orgs, sandboxes, production orgs) with aliases, usernames, and expiry dates.

If CLI is not installed, returns installation instructions and the current connected org's URL as fallback.`,
      inputSchema: external_exports.object({}).strict(),
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async () => {
      const result = await client.listAllOrgs();
      return ok(result);
    }
  );
  server.registerTool(
    "sf_create_scratch_org",
    {
      title: "Create Scratch Org",
      description: `Create a new Salesforce scratch org via the Salesforce CLI.

Requires: Salesforce CLI (sf) installed + a Dev Hub org authorized locally.

Args:
  - alias (string): Short alias for the scratch org, e.g. 'feature-branch-42'
  - edition: developer | enterprise | group | professional | partner-developer (default: developer)
  - duration_days (number): Lifetime in days, 1-30 (default: 7)
  - dev_hub_alias (string, optional): Dev Hub alias (uses default if not set)
  - definition_file (string, optional): Path to scratch org definition JSON (overrides edition)
  - no_namespace (boolean): Create without namespace (default: false)

Returns: Scratch org details including username, instance URL, and org ID.

If CLI is not installed, returns installation instructions.

Example:
  { alias: "sprint-47-dev", edition: "developer", duration_days: 14 }`,
      inputSchema: CreateScratchOrgSchema,
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: false, openWorldHint: true }
    },
    async ({ alias, edition, duration_days, dev_hub_alias, definition_file, no_namespace }) => {
      const result = await client.createScratchOrg({
        alias,
        edition,
        durationDays: duration_days,
        devHubAlias: dev_hub_alias,
        definitionFile: definition_file,
        noNamespace: no_namespace
      });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_delete_scratch_org",
    {
      title: "Delete Scratch Org",
      description: `Delete a Salesforce scratch org by alias or username.

Requires Salesforce CLI.

Args:
  - alias_or_username (string): Org alias or username to delete

\u26A0\uFE0F Permanent. The scratch org and all its data will be deleted.`,
      inputSchema: OrgAliasSchema,
      annotations: { readOnlyHint: false, destructiveHint: true, idempotentHint: false, openWorldHint: false }
    },
    async ({ alias_or_username }) => {
      if (!alias_or_username) return { content: [{ type: "text", text: JSON.stringify({ error: "alias_or_username is required" }) }] };
      const result = await client.deleteScratchOrg(alias_or_username);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_open_org",
    {
      title: "Open Org in Browser / Get Login URL",
      description: `Get the browser login URL for a Salesforce org. Opens via CLI if available, otherwise returns the instance URL.

Args:
  - alias_or_username (string, optional): Org alias or username (uses current connected org if not specified)

Returns: Login URL for the org.`,
      inputSchema: OrgAliasSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ alias_or_username }) => {
      const result = await client.openOrg(alias_or_username);
      return ok(result);
    }
  );
}

// src/tools/bulk.ts
function registerBulkTools(server, client) {
  server.registerTool(
    "sf_bulk_ingest",
    {
      title: "Bulk 2.0 Ingest (Millions of Records)",
      description: `Create and upload a Bulk 2.0 ingest job \u2014 insert, update, upsert, delete, or hardDelete millions of records.

Handles the full flow: create job \u2192 convert records to CSV \u2192 upload \u2192 close. Returns a jobId immediately.
Processing happens asynchronously. Use sf_get_bulk_job_status to track, sf_get_bulk_job_results for outcomes.

Args:
  - sobject (string): Salesforce object API name
  - operation: insert | update | upsert | delete | hardDelete
  - records (array): JSON array of records. For delete/hardDelete only Id field needed.
  - external_id_field (string): Required for upsert \u2014 external ID field API name

Returns: { jobId, recordCount, state, message }

Examples:
  - Bulk insert leads:
    { sobject: "Lead", operation: "insert", records: [{ "FirstName": "Alice", "LastName": "Smith", "Company": "Acme", "Email": "alice@acme.com" }, ...] }

  - Bulk update opportunity stages:
    { sobject: "Opportunity", operation: "update", records: [{ "Id": "006XXX", "StageName": "Closed Won" }, ...] }

  - Bulk upsert accounts by external ID:
    { sobject: "Account", operation: "upsert", external_id_field: "SAP_Id__c", records: [{ "SAP_Id__c": "SAP-001", "Name": "Acme Corp" }, ...] }

  - Bulk delete old records:
    { sobject: "Lead", operation: "delete", records: [{ "Id": "00QXX001" }, { "Id": "00QXX002" }, ...] }

\u26A0\uFE0F hardDelete bypasses the Recycle Bin \u2014 permanent, unrecoverable.`,
      inputSchema: BulkIngestSchema,
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: false, openWorldHint: false }
    },
    async ({ sobject, operation, records, external_id_field }) => {
      const result = await client.bulkIngest({
        sobject,
        operation,
        records,
        externalIdFieldName: external_id_field
      });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_get_bulk_job_status",
    {
      title: "Get Bulk Job Status",
      description: `Get current status of a Bulk 2.0 job (ingest or query).

Args:
  - job_id (string): Bulk job ID from sf_bulk_ingest or sf_bulk_query_create
  - job_type: "ingest" (default) | "query"

Returns: Job state, records processed, records failed, and timing info.

Job states:
  Open \u2192 UploadComplete \u2192 InProgress \u2192 JobComplete | Failed | Aborted

When state = JobComplete:
  - Call sf_get_bulk_job_results for successfulResults and failedResults (ingest)
  - Call sf_get_bulk_query_results for data (query)`,
      inputSchema: BulkJobIdSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ job_id, job_type }) => {
      const result = await client.getBulkJobStatus(job_id, job_type);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_list_bulk_jobs",
    {
      title: "List Bulk Jobs",
      description: `List all Bulk 2.0 jobs in the org (recent jobs, all states).

Args:
  - job_type: "ingest" (default) | "query"

Returns: All bulk jobs with ID, object, operation, state, record counts, and dates.`,
      inputSchema: ListBulkJobsSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ job_type }) => {
      const result = await client.listBulkJobs(job_type);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_get_bulk_job_results",
    {
      title: "Get Bulk Ingest Job Results",
      description: `Retrieve success, failure, or unprocessed records from a completed Bulk 2.0 ingest job.

Only available when job state = JobComplete.

Args:
  - job_id (string): Bulk ingest job ID
  - result_type: "successfulResults" | "failedResults" | "unprocessedrecords"
  - max_records (number): Max records to return (default: 1000, max: 50000)

Returns: Array of records with sf__Id, sf__Created (for inserts), or sf__Error (for failures).

Workflow:
  1. sf_bulk_ingest \u2192 get jobId
  2. sf_get_bulk_job_status \u2192 wait for JobComplete
  3. sf_get_bulk_job_results with result_type: "successfulResults" \u2192 IDs of created/updated records
  4. sf_get_bulk_job_results with result_type: "failedResults" \u2192 failed records with error messages`,
      inputSchema: BulkJobResultsSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ job_id, result_type, max_records }) => {
      const result = await client.getBulkJobResults({
        jobId: job_id,
        resultType: result_type,
        maxRecords: max_records
      });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_abort_bulk_job",
    {
      title: "Abort Bulk Job",
      description: `Abort a running or queued Bulk 2.0 ingest job. Processed records are NOT rolled back.

Args:
  - job_id (string): Bulk ingest job ID to abort
  - job_type: "ingest" (default)

\u26A0\uFE0F Records already processed before abort are committed. Only unprocessed records are skipped.`,
      inputSchema: BulkJobIdSchema,
      annotations: { readOnlyHint: false, destructiveHint: true, idempotentHint: false, openWorldHint: false }
    },
    async ({ job_id }) => {
      const result = await client.bulkIngestAbort(job_id);
      return ok(result);
    }
  );
  server.registerTool(
    "sf_bulk_query",
    {
      title: "Bulk Query (Millions of Records)",
      description: `Execute a SOQL query via Bulk 2.0 API to retrieve millions of records \u2014 no governor limits on result size.

Creates a query job, waits for completion, and returns results directly. For queries that may return
more records than the max_records limit, a nextLocator is returned \u2014 use sf_get_bulk_query_results to paginate.

Use this instead of sf_query when:
  - You expect >50,000 records
  - You're doing data migrations, backups, or mass exports
  - You're hitting SOQL row limits with the standard API

Args:
  - soql (string): SOQL query (no LIMIT needed \u2014 Bulk handles pagination internally)
  - max_records (number): Max records to return in one call (default: 50000)
  - poll_interval_seconds (number): How often to check status (default: 5s)
  - max_poll_seconds (number): Max wait time (default: 120s)

Returns: { jobId, records, count, done, truncated }
  - done: true = all records returned
  - truncated: true = use sf_get_bulk_query_results with nextLocator for more

Examples:
  - Export all accounts: { soql: "SELECT Id, Name, Industry, AnnualRevenue FROM Account" }
  - Export all contacts with emails: { soql: "SELECT Id, FirstName, LastName, Email, AccountId FROM Contact WHERE Email != null" }
  - Audit log: { soql: "SELECT Id, UserId, Action, EntityType, CreatedDate FROM SetupAuditTrail ORDER BY CreatedDate DESC" }`,
      inputSchema: BulkQuerySchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: false, openWorldHint: false }
    },
    async ({ soql, max_records, poll_interval_seconds, max_poll_seconds }) => {
      const result = await client.bulkQuery({
        soql,
        maxRecords: max_records,
        pollIntervalSeconds: poll_interval_seconds,
        maxPollSeconds: max_poll_seconds
      });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_get_bulk_query_results",
    {
      title: "Get Bulk Query Results (Paginated)",
      description: `Retrieve results from a completed Bulk 2.0 query job, with pagination support for massive result sets.

Use this when sf_bulk_query returns truncated: true (result set larger than max_records).

Args:
  - job_id (string): Bulk query job ID from sf_bulk_query
  - max_records (number): Records per page (default: 50000)
  - locator (string): nextLocator value from previous call for pagination

Returns: { records, count, nextLocator, done }
  - Keep calling with nextLocator until done = true to get all records.

Pagination pattern:
  1. sf_bulk_query \u2192 { jobId, records, nextLocator, done: false }
  2. sf_get_bulk_query_results { job_id, locator: nextLocator } \u2192 next page
  3. Repeat until done = true`,
      inputSchema: BulkQueryResultsSchema,
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async ({ job_id, max_records, locator }) => {
      const result = await client.getBulkQueryResults({
        jobId: job_id,
        maxRecords: max_records,
        locator
      });
      return ok(result);
    }
  );
  server.registerTool(
    "sf_get_auth_info",
    {
      title: "Get Auth Info",
      description: `Get information about the current authentication mode and connected org.

No args required.

Returns: Auth mode (password/jwt), connected org URL, API version, and username.
Useful for verifying which org and auth method the MCP is currently using.`,
      inputSchema: external_exports.object({}).strict(),
      annotations: { readOnlyHint: true, destructiveHint: false, idempotentHint: true, openWorldHint: false }
    },
    async () => {
      const instanceUrl = client.getInstanceUrl();
      const authMode = client.getAuthMode();
      const result = {
        authMode,
        instanceUrl: instanceUrl || "Not yet authenticated",
        description: authMode === "jwt" ? "JWT Bearer Token \u2014 passwordless, production-grade server-to-server auth. Token auto-refreshes." : "Username + Password OAuth \u2014 suitable for development. Enable in Connected App policies."
      };
      return ok(result);
    }
  );
}

// src/index.ts
function getConfig() {
  const authMode = process.env.SF_AUTH_MODE ?? "password";
  const loginUrl = process.env.SF_LOGIN_URL;
  const clientId = process.env.SF_CLIENT_ID;
  const username = process.env.SF_USERNAME;
  const missingCommon = ["SF_LOGIN_URL", "SF_CLIENT_ID", "SF_USERNAME"].filter(
    (k) => !process.env[k]
  );
  if (missingCommon.length) {
    console.error(`\u274C Missing required env vars: ${missingCommon.join(", ")}`);
    process.exit(1);
  }
  if (authMode === "jwt") {
    if (!process.env.SF_PRIVATE_KEY && !process.env.SF_PRIVATE_KEY_FILE) {
      console.error(
        "\u274C JWT auth requires SF_PRIVATE_KEY (PEM string) or SF_PRIVATE_KEY_FILE (path to .key/.pem)\n\nJWT Connected App Setup:\n  1. Setup \u2192 App Manager \u2192 New Connected App\n  2. Enable OAuth, add 'full' scope\n  3. Enable 'Use digital signatures' and upload your certificate (.crt)\n  4. Setup \u2192 Manage Connected Apps \u2192 your app \u2192 Edit Policies \u2192 Permitted Users: Admin approved\n  5. Generate key pair: openssl genrsa -out server.key 2048 && openssl req -new -x509 -key server.key -out server.crt -days 3650\n  6. Set SF_PRIVATE_KEY_FILE=./server.key or paste PEM into SF_PRIVATE_KEY"
      );
      process.exit(1);
    }
    console.error("\u{1F510} Auth mode: JWT Bearer Token (passwordless)");
    return {
      loginUrl,
      clientId,
      username,
      apiVersion: process.env.SF_API_VERSION ?? "v60.0",
      authMode: "jwt",
      privateKey: process.env.SF_PRIVATE_KEY,
      privateKeyFile: process.env.SF_PRIVATE_KEY_FILE
    };
  }
  const missingPassword = ["SF_CLIENT_SECRET", "SF_PASSWORD"].filter((k) => !process.env[k]);
  if (missingPassword.length) {
    console.error(
      `\u274C Password auth requires: ${missingPassword.join(", ")}

Or switch to JWT auth: set SF_AUTH_MODE=jwt (no password required)

Required env vars for password auth:
  SF_LOGIN_URL=https://login.salesforce.com
  SF_CLIENT_ID=your_consumer_key
  SF_CLIENT_SECRET=your_consumer_secret
  SF_USERNAME=user@yourorg.com
  SF_PASSWORD=yourpassword
  SF_SECURITY_TOKEN=yourtoken   # optional if IP is whitelisted
  SF_API_VERSION=v60.0          # optional
`
    );
    process.exit(1);
  }
  console.error("\u{1F511} Auth mode: Username + Password");
  return {
    loginUrl,
    clientId,
    username,
    apiVersion: process.env.SF_API_VERSION ?? "v60.0",
    authMode: "password",
    clientSecret: process.env.SF_CLIENT_SECRET,
    password: process.env.SF_PASSWORD,
    securityToken: process.env.SF_SECURITY_TOKEN ?? ""
  };
}
